# Terraform snippet: Cloud Run + Cloud SQL integration
# (illustrates how infrastructure-as-code ties services together)
resource "google_cloud_run_v2_service" "agent_api" {
  name     = "agent-api"
  location = "us-central1"

  template {
    service_account = google_service_account.agent_api.email
    scaling { min_instance_count = 1 max_instance_count = 20 }

    volumes {
      name = "cloudsql"
      cloud_sql_instance { instances = [google_sql_database_instance.main.connection_name] }
    }

    containers {
      image = "us-central1-docker.pkg.dev/${var.project}/agent-images/agent-api:latest"
      env {
        name = "DB_PASSWORD"
        value_source { secret_key_ref { secret = google_secret_manager_secret.db_password.secret_id version = "latest" } }
      }
      volume_mounts { name = "cloudsql" mount_path = "/cloudsql" }
      resources { limits = { cpu = "2", memory = "2Gi" } }
    }
  }
}
